import base64
import json


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing JSON user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize the preferences object using JSON instead of pickle
        # This prevents arbitrary code execution vulnerabilities
        preferences = json.loads(decoded_data)
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        # Return empty dict or handle error appropriately if the input is malformed
        return {}

    # Ensure we return a dictionary
    if isinstance(preferences, dict):
        return preferences

    return {}

